#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeSonarIdentity: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = SonarIdentity

    public static func lift(_ handle: UInt64) throws -> SonarIdentity {
        return SonarIdentity(unsafeFromHandle: handle)
    }

    public static func lower(_ value: SonarIdentity) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SonarIdentity {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: SonarIdentity, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeSonarIdentity_lift(_ handle: UInt64) throws -> SonarIdentity {
    return try FfiConverterTypeSonarIdentity.lift(handle)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeSonarIdentity_lower(_ value: SonarIdentity) -> UInt64 {
    return FfiConverterTypeSonarIdentity.lower(value)
}






/**
 * A relay-connected Sonar node. Owns its own tokio runtime; every method is
 * blocking — call from a background queue in Swift, never the main thread.
