    return try  FfiConverterTypeSonarNoise_lift(try rustCallWithError(FfiConverterTypeSonarFfiError_lift) {
    uniffi_sonar_ffi_fn_constructor_sonarnoise_initiator(
        FfiConverterString.lower(privateHex),$0
